/**
 * OUROZ – Homepage / Landing Page
 * Server Component – showcases brand story, featured categories, and CTA.
 */

import Link from 'next/link';
import { cookies } from 'next/headers';
import { fetchCategories, fetchBrands } from '@/lib/api';
import type { LangCode } from '@/types/shop';

export const revalidate = 60;

export default async function HomePage() {
    const cookieStore = await cookies();
    const lang = (cookieStore.get('ouroz_lang')?.value ?? 'en') as LangCode;

    const [categories, brands] = await Promise.all([
        fetchCategories(),
        fetchBrands(),
    ]);

    const topCategories = categories.slice(0, 6);
    const topBrands = brands.filter(b => b.logo_url).slice(0, 8);

    const t = {
        hero: {
            en: 'Authentic Moroccan Products, Delivered in Dubai',
            ar: 'منتجات مغربية أصيلة، توصيل في دبي',
            fr: 'Produits Marocains Authentiques, Livrés à Dubaï',
        },
        sub: {
            en: 'From the souks of Morocco to your doorstep. Fresh spices, artisan goods, and traditional delicacies.',
            ar: 'من أسواق المغرب إلى بابك. توابل طازجة وحرف يدوية وأطباق تقليدية.',
            fr: 'Des souks du Maroc à votre porte. Épices fraîches, artisanat et délices traditionnels.',
        },
        shopNow: { en: 'Shop Now', ar: 'تسوق الآن', fr: 'Acheter' },
        supplier: { en: 'Become a Supplier', ar: 'كن مورداً', fr: 'Devenir Fournisseur' },
        categories: { en: 'Shop by Category', ar: 'تسوق حسب الفئة', fr: 'Par Catégorie' },
        brands: { en: 'Our Brands', ar: 'علاماتنا التجارية', fr: 'Nos Marques' },
        why: { en: 'Why OUROZ?', ar: 'لماذا أوروز؟', fr: 'Pourquoi OUROZ ?' },
    };

    return (
        <div className="min-h-screen">
            {/* ── Navbar ─────────────────────────────────────────────── */}
            <header className="sticky top-0 z-30 bg-[var(--color-sahara)]/95 backdrop-blur border-b border-stone-200">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 h-14 flex items-center justify-between">
                    <Link href="/" className="flex items-center gap-2">
                        <div className="w-8 h-8 bg-gradient-to-br from-amber-600 to-amber-800 rounded-full flex items-center justify-center">
                            <span className="text-white font-serif text-sm">ⵣ</span>
                        </div>
                        <span className="text-xl font-serif font-bold text-[var(--color-charcoal)]">OUROZ</span>
                    </Link>
                    <nav className="flex items-center gap-6">
                        <Link href="/shop" className="text-sm font-medium text-[var(--color-charcoal)]/70 hover:text-[var(--color-charcoal)] transition">
                            {t.shopNow[lang]}
                        </Link>
                        <Link href="/supplier/register" className="text-sm font-medium text-[var(--color-charcoal)]/70 hover:text-[var(--color-charcoal)] transition">
                            {t.supplier[lang]}
                        </Link>
                        <Link href="/auth/login" className="text-sm px-4 py-2 bg-amber-600 text-white rounded-xl font-medium hover:bg-amber-700 transition">
                            Sign In
                        </Link>
                    </nav>
                </div>
            </header>

            {/* ── Hero ────────────────────────────────────────────────── */}
            <section className="relative overflow-hidden bg-gradient-to-br from-[var(--color-imperial)]/90 to-[var(--color-charcoal)] text-white">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 py-20 md:py-28 relative z-10">
                    <div className="max-w-2xl">
                        <p className="text-sm font-semibold uppercase tracking-widest text-[var(--color-gold)] mb-4">
                            OUROZ – دبي
                        </p>
                        <h1 className="text-4xl md:text-5xl font-bold leading-tight mb-6">
                            {t.hero[lang]}
                        </h1>
                        <p className="text-lg text-white/70 mb-8 max-w-lg">
                            {t.sub[lang]}
                        </p>
                        <div className="flex flex-wrap gap-4">
                            <Link href="/shop"
                                className="px-8 py-3.5 bg-amber-600 text-white rounded-xl font-semibold hover:bg-amber-700 transition text-sm">
                                {t.shopNow[lang]}
                            </Link>
                            <Link href="/wholesale/apply"
                                className="px-8 py-3.5 border border-white/30 text-white rounded-xl font-medium hover:bg-white/10 transition text-sm">
                                Wholesale Pricing
                            </Link>
                        </div>
                    </div>
                </div>
                <div className="absolute inset-0 opacity-10 pointer-events-none"
                    style={{ backgroundImage: 'url(/patterns/zellige.svg)', backgroundSize: '80px' }} />
            </section>

            {/* ── Categories ──────────────────────────────────────────── */}
            {topCategories.length > 0 && (
                <section className="max-w-7xl mx-auto px-4 sm:px-6 py-16">
                    <h2 className="text-2xl font-bold text-[var(--color-charcoal)] mb-8 text-center">
                        {t.categories[lang]}
                    </h2>
                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
                        {topCategories.map(cat => {
                            const name = lang === 'ar' && cat.name_ar ? cat.name_ar : lang === 'fr' && cat.name_fr ? cat.name_fr : cat.name;
                            return (
                                <Link key={cat.id} href={`/shop/${cat.slug}`}
                                    className="group bg-white rounded-2xl p-5 border border-gray-100 hover:border-amber-200 hover:shadow-md transition text-center">
                                    {cat.image_url ? (
                                        <img src={cat.image_url} alt={name} className="w-16 h-16 mx-auto mb-3 rounded-xl object-cover" />
                                    ) : (
                                        <div className="w-16 h-16 mx-auto mb-3 rounded-xl bg-amber-50 flex items-center justify-center text-2xl">
                                            {cat.icon ?? '◆'}
                                        </div>
                                    )}
                                    <p className="text-sm font-semibold text-gray-800 group-hover:text-amber-600 transition">{name}</p>
                                </Link>
                            );
                        })}
                    </div>
                </section>
            )}

            {/* ── Why OUROZ ───────────────────────────────────────────── */}
            <section className="bg-white py-16">
                <div className="max-w-7xl mx-auto px-4 sm:px-6">
                    <h2 className="text-2xl font-bold text-[var(--color-charcoal)] mb-10 text-center">
                        {t.why[lang]}
                    </h2>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {[
                            { icon: '🌿', title: 'Direct from Morocco', desc: 'Sourced directly from Moroccan artisans and cooperatives, ensuring authenticity and fair trade.' },
                            { icon: '🚚', title: 'Fast Dubai Delivery', desc: 'Same-day and next-day delivery across all Emirates. Fresh products guaranteed.' },
                            { icon: '💎', title: 'Wholesale & Retail', desc: 'Competitive pricing for businesses. Tiered wholesale rates with credit terms for approved accounts.' },
                        ].map(card => (
                            <div key={card.title} className="text-center p-6">
                                <div className="text-4xl mb-4">{card.icon}</div>
                                <h3 className="text-lg font-bold text-[var(--color-charcoal)] mb-2">{card.title}</h3>
                                <p className="text-sm text-gray-500 leading-relaxed">{card.desc}</p>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* ── Brands ──────────────────────────────────────────────── */}
            {topBrands.length > 0 && (
                <section className="max-w-7xl mx-auto px-4 sm:px-6 py-16">
                    <h2 className="text-2xl font-bold text-[var(--color-charcoal)] mb-8 text-center">
                        {t.brands[lang]}
                    </h2>
                    <div className="flex flex-wrap justify-center gap-8 items-center">
                        {topBrands.map(brand => (
                            <div key={brand.id} className="w-24 h-16 flex items-center justify-center opacity-60 hover:opacity-100 transition">
                                {brand.logo_url ? (
                                    <img src={brand.logo_url} alt={brand.name} className="max-w-full max-h-full object-contain" />
                                ) : (
                                    <span className="text-sm font-bold text-gray-400">{brand.name}</span>
                                )}
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {/* ── CTA ─────────────────────────────────────────────────── */}
            <section className="bg-gradient-to-r from-amber-600 to-amber-800 text-white py-16">
                <div className="max-w-3xl mx-auto px-4 text-center">
                    <h2 className="text-3xl font-bold mb-4">Ready to explore?</h2>
                    <p className="text-white/80 mb-8">Browse hundreds of authentic Moroccan products, from spices to skincare.</p>
                    <Link href="/shop"
                        className="inline-block px-10 py-4 bg-white text-amber-700 rounded-xl font-bold hover:bg-amber-50 transition">
                        {t.shopNow[lang]}
                    </Link>
                </div>
            </section>

            {/* ── Footer ──────────────────────────────────────────────── */}
            <footer className="bg-[var(--color-charcoal)] text-white/60 py-12">
                <div className="max-w-7xl mx-auto px-4 sm:px-6">
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-8 mb-8">
                        <div>
                            <div className="flex items-center gap-2 mb-3">
                                <div className="w-8 h-8 bg-gradient-to-br from-amber-600 to-amber-800 rounded-full flex items-center justify-center">
                                    <span className="text-white font-serif text-sm">ⵣ</span>
                                </div>
                                <span className="text-lg font-serif font-bold text-white">OUROZ</span>
                            </div>
                            <p className="text-sm">Authentic Moroccan products, delivered to your door in the UAE.</p>
                        </div>
                        <div>
                            <h4 className="text-white font-semibold text-sm mb-3">Shop</h4>
                            <ul className="space-y-2 text-sm">
                                <li><Link href="/shop" className="hover:text-white transition">All Products</Link></li>
                                <li><Link href="/wholesale/apply" className="hover:text-white transition">Wholesale</Link></li>
                            </ul>
                        </div>
                        <div>
                            <h4 className="text-white font-semibold text-sm mb-3">Sell</h4>
                            <ul className="space-y-2 text-sm">
                                <li><Link href="/supplier/register" className="hover:text-white transition">Become a Supplier</Link></li>
                                <li><Link href="/supplier/dashboard" className="hover:text-white transition">Supplier Portal</Link></li>
                            </ul>
                        </div>
                        <div>
                            <h4 className="text-white font-semibold text-sm mb-3">Account</h4>
                            <ul className="space-y-2 text-sm">
                                <li><Link href="/auth/login" className="hover:text-white transition">Sign In</Link></li>
                                <li><Link href="/auth/signup" className="hover:text-white transition">Create Account</Link></li>
                                <li><Link href="/account" className="hover:text-white transition">My Account</Link></li>
                            </ul>
                        </div>
                    </div>
                    <div className="border-t border-white/10 pt-6 text-center text-xs">
                        <p>&copy; {new Date().getFullYear()} OUROZ. All rights reserved.</p>
                    </div>
                </div>
            </footer>
        </div>
    );
}
